            if (result.length > 0) {
                result = result.slice(0, -1);
            }
        } else if (c === '#') {
            result += result;
        } else if (c === '%') {
            result = result.split('').reverse().join('');
        } else if (c >= 'a' && c <= 'z') {
            result += c;
        }
    }
    return result;
}
```

